-- 00169: elaborate the 41 competency definitions (EN + AR), 3 sentences each.
-- Definitions only; behavioural indicators unchanged. Idempotent UPDATE by id.

UPDATE competencies SET description = 'Anticipates how markets, regulation, and client needs are likely to shift, and translates that foresight into a clear, prioritised strategic direction. Looks beyond immediate pressures to position the organisation for future advantage, framing choices around long-term value rather than short-term convenience. Sets direction that others can understand, align to, and act on with confidence.', description_ar = 'يستشرف كيف ستتغيّر الأسواق والتشريعات واحتياجات العملاء، ويحوّل هذه الرؤية المستقبلية إلى توجّه استراتيجي واضح ومرتّب الأولويات. ينظر إلى ما هو أبعد من الضغوط الآنية ليضع المنظمة في موقعٍ تنافسي مستقبلي، مؤطّراً خياراته حول القيمة بعيدة المدى لا المنفعة قصيرة الأجل. يرسم اتجاهاً يستطيع الآخرون فهمه والاصطفاف خلفه والعمل وفقه بثقة.' WHERE id = 'a0000001-0000-0000-0000-000000000001';
UPDATE competencies SET description = 'Reads the competitive, economic, and regulatory landscape to spot the opportunities and risks that matter to the organisation''s goals. Connects external signals such as competitors, clients, and market or policy shifts to internal choices about where to focus and invest. Uses that awareness to advance commercial outcomes rather than to observe from the sidelines.', description_ar = 'يقرأ المشهد التنافسي والاقتصادي والتنظيمي لرصد الفرص والمخاطر ذات الأثر على أهداف المنظمة. يربط الإشارات الخارجية — كالمنافسين والعملاء وتحوّلات السوق والسياسات — بالقرارات الداخلية حول أين يركّز وأين يستثمر. يوظّف هذا الوعي لتعزيز النتائج التجارية لا للاكتفاء بالمراقبة من بعيد.' WHERE id = 'a0000001-0000-0000-0000-000000000002';
UPDATE competencies SET description = 'Interprets financial statements, ratios, and capital and liquidity indicators, and understands what they reveal about performance and risk. Uses that understanding to weigh trade-offs, test the numbers behind a proposal, and justify decisions in commercial terms. Brings financial discipline to choices so that value, cost, and risk are properly balanced.', description_ar = 'يفسّر القوائم المالية والنسب ومؤشّرات رأس المال والسيولة، ويدرك ما تكشفه عن الأداء والمخاطر. يستخدم هذا الفهم للموازنة بين البدائل، واختبار الأرقام التي يقوم عليها أيّ مقترح، وتبرير القرارات بلغةٍ تجارية. يُضفي انضباطاً مالياً على الخيارات بحيث تتوازن القيمة والكلفة والمخاطر.' WHERE id = 'a0000001-0000-0000-0000-000000000003';
UPDATE competencies SET description = 'Breaks ambiguous, data-heavy problems into their parts and examines them rigorously rather than reaching for the first answer. Tests assumptions, distinguishes evidence from opinion, and weighs competing explanations before drawing a conclusion. Produces reasoning that holds up to scrutiny and leads to sound, defensible decisions.', description_ar = 'يفكّك المشكلات الغامضة والغنيّة بالبيانات إلى عناصرها ويفحصها بدقّة بدلاً من التسرّع إلى أوّل إجابة. يختبر الافتراضات، ويميّز الأدلّة عن الآراء، ويوازن بين التفسيرات المتنافسة قبل الوصول إلى استنتاج. يُنتج تحليلاً يصمد أمام التدقيق ويُفضي إلى قرارات سليمة قابلة للدفاع عنها.' WHERE id = 'a0000001-0000-0000-0000-000000000004';
UPDATE competencies SET description = 'Makes timely, balanced decisions even when information is incomplete or conditions are uncertain. Weighs risk, stakeholders, and the second-order consequences of a choice rather than only its immediate effect. Knows when to decide and when to wait, and stands behind decisions with clear reasoning.', description_ar = 'يتّخذ قرارات متوازنة وفي الوقت المناسب حتى حين تكون المعلومات ناقصة أو الظروف غير مؤكّدة. يوازن بين المخاطر وأصحاب المصلحة والتبعات غير المباشرة للقرار لا أثره الآني فحسب. يدرك متى يقرّر ومتى ينتظر، ويقف خلف قراراته بمنطقٍ واضح.' WHERE id = 'a0000001-0000-0000-0000-000000000005';
UPDATE competencies SET description = 'Generates and tests original approaches that improve products, processes, or outcomes instead of defaulting to precedent. Challenges the way things have always been done and is willing to try, learn, and refine new ideas. Turns creativity into practical improvement that the organisation can actually use.', description_ar = 'يبتكر ويختبر مقاربات أصيلة تحسّن المنتجات أو العمليات أو النتائج بدلاً من الركون إلى ما سبق. يتحدّى منطق «هكذا كنّا نفعل دائماً»، ويستعدّ لتجربة الأفكار الجديدة والتعلّم منها وصقلها. يحوّل الإبداع إلى تحسينٍ عملي يمكن للمنظمة الاستفادة منه فعلاً.' WHERE id = 'a0000001-0000-0000-0000-000000000006';
UPDATE competencies SET description = 'Makes sense of high-volume, interdependent, and sometimes conflicting information to define what the real problem is. Sees patterns and connections across moving parts rather than getting lost in detail or oversimplifying. Brings clarity to complicated situations so that the organisation can act on them.', description_ar = 'يستوعب المعلومات الكثيفة والمترابطة والمتعارضة أحياناً ليحدّد ما هي المشكلة الحقيقية. يرى الأنماط والروابط عبر الأجزاء المتحرّكة دون أن يضيع في التفاصيل أو يُفرط في التبسيط. يُضفي وضوحاً على المواقف المعقّدة بما يمكّن المنظمة من التعامل معها.' WHERE id = 'a0000001-0000-0000-0000-000000000007';
UPDATE competencies SET description = 'Considers the wider system, across borders, functions, and the macro-economy, when framing issues and weighing impact. Looks beyond a single team or market to how decisions ripple across the whole and over time. Brings a broad, joined-up lens that prevents narrow or short-sighted choices.', description_ar = 'يأخذ في الحسبان المنظومة الأوسع — العابرة للحدود والوظائف والاقتصاد الكلّي — عند تأطير القضايا وتقدير الأثر. ينظر إلى ما هو أبعد من فريقٍ أو سوقٍ واحد ليرى كيف تتردّد آثار القرارات عبر الكلّ وعبر الزمن. يقدّم عدسةً واسعة ومترابطة تقي من الخيارات الضيّقة أو قصيرة النظر.' WHERE id = 'a0000001-0000-0000-0000-000000000008';
UPDATE competencies SET description = 'Applies digital tools, automation, and data analysis to improve how work gets done and how decisions get made. Is comfortable using technology and evidence rather than relying on habit or instinct alone. Helps the organisation work smarter by turning data and digital capability into better outcomes.', description_ar = 'يوظّف الأدوات الرقمية والأتمتة وتحليل البيانات لتحسين طريقة إنجاز العمل واتّخاذ القرار. يرتاح إلى استخدام التقنية والأدلّة بدلاً من الاعتماد على العادة أو الحدس وحده. يساعد المنظمة على العمل بذكاءٍ أكبر بتحويل البيانات والقدرات الرقمية إلى نتائج أفضل.' WHERE id = 'a0000001-0000-0000-0000-000000000009';
UPDATE competencies SET description = 'Moves on opportunities and tough challenges early and with energy, rather than waiting to be directed. Spots what needs doing and starts it, taking ownership before being asked. Creates momentum that pulls work and people forward instead of letting things drift.', description_ar = 'يبادر إلى الفرص والتحدّيات الصعبة مبكّراً وبحماس، بدلاً من انتظار التوجيه. يلتقط ما يجب فعله ويبدأ به متحمّلاً المسؤولية قبل أن يُطلب منه. يصنع زخماً يدفع العمل والناس إلى الأمام بدلاً من ترك الأمور تتباطأ.' WHERE id = 'a0000001-0000-0000-0000-000000000010';
UPDATE competencies SET description = 'Takes personal responsibility for delivering measurable results, not just activity, and follows through from commitment to completion. Sustains effort, quality, and standards even when conditions are difficult, resources are tight, or obstacles emerge. Steps up to close gaps rather than explain them away.', description_ar = 'يتحمّل مسؤولية شخصية عن تحقيق نتائج قابلة للقياس لا مجرّد نشاط، ويتابع من الالتزام حتى الإنجاز. يحافظ على الجهد والجودة والمعايير حتى حين تصعب الظروف أو تشحّ الموارد أو تظهر العقبات. يبادر إلى سدّ الثغرات بدلاً من تبريرها.' WHERE id = 'a0000001-0000-0000-0000-000000000011';
UPDATE competencies SET description = 'Holds self and others to what was promised, following through transparently on deadlines and quality. Owns mistakes openly and fixes them rather than shifting blame or letting commitments slip quietly. Builds a track record of reliability that the organisation can plan around.', description_ar = 'يُلزم نفسه والآخرين بما تمّ التعهّد به، ويتابع بشفافية ما يتعلّق بالمواعيد والجودة. يعترف بالأخطاء بصراحة ويصحّحها بدلاً من إلقاء اللوم أو التفريط بالالتزامات بهدوء. يبني سجلّاً من الموثوقية تستطيع المنظمة الاعتماد عليه في التخطيط.' WHERE id = 'a0000001-0000-0000-0000-000000000012';
UPDATE competencies SET description = 'Sequences and resources work so the most important commitments are met in line with organisational goals. Distinguishes the urgent from the important and allocates time, people, and budget accordingly. Keeps delivery on track by anticipating dependencies and adjusting plans as conditions change.', description_ar = 'يرتّب العمل ويوفّر له الموارد بحيث تُنجَز أهمّ الالتزامات بما يتماشى مع أهداف المنظمة. يميّز بين العاجل والمهمّ ويوزّع الوقت والأشخاص والميزانية وفق ذلك. يُبقي التنفيذ على المسار باستباق التبعات وتعديل الخطط مع تغيّر الظروف.' WHERE id = 'a0000001-0000-0000-0000-000000000013';
UPDATE competencies SET description = 'Designs and improves workflows for efficiency and control, removing waste without sacrificing compliance or quality. Looks for the better way of working and embeds continuous improvement rather than tolerating recurring friction. Makes processes more reliable, faster, and easier for people to follow.', description_ar = 'يصمّم سير العمل ويحسّنه لتحقيق الكفاءة والضبط، مزيلاً الهدر دون التفريط بالامتثال أو الجودة. يبحث عن الطريقة الأفضل للعمل ويرسّخ التحسين المستمرّ بدلاً من التسامح مع الاحتكاك المتكرّر. يجعل العمليات أكثر موثوقية وسرعة وأيسر على الناس اتّباعاً.' WHERE id = 'a0000001-0000-0000-0000-000000000014';
UPDATE competencies SET description = 'Stays effective and decisive when direction, data, or conditions are unclear or shifting. Makes reasonable progress on the basis of what is known, adjusting course as new information arrives rather than freezing. Provides steadiness that helps others keep moving through ambiguity.', description_ar = 'يبقى فاعلاً وحاسماً حين يكون الاتجاه أو البيانات أو الظروف غير واضحة أو متغيّرة. يُحرز تقدّماً معقولاً بناءً على المتاح من المعطيات، معدّلاً مساره مع وصول معلومات جديدة بدلاً من التجمّد. يوفّر ثباتاً يعين الآخرين على مواصلة التقدّم وسط الغموض.' WHERE id = 'a0000001-0000-0000-0000-000000000015';
UPDATE competencies SET description = 'Experiments when facing unfamiliar problems and adjusts quickly, treating both wins and failures as information. Prefers to test, learn, and refine in practice rather than wait for perfect certainty before acting. Builds know-how through hands-on iteration that compounds over time.', description_ar = 'يجرّب عند مواجهة مشكلات غير مألوفة ويعدّل بسرعة، متعاملاً مع النجاحات والإخفاقات كمصدرٍ للمعرفة. يفضّل الاختبار والتعلّم والصقل في الممارسة بدلاً من انتظار اليقين التامّ قبل الإقدام. يبني الخبرة عبر تكرارٍ عملي يتراكم أثره مع الوقت.' WHERE id = 'a0000001-0000-0000-0000-000000000016';
UPDATE competencies SET description = 'Maintains performance, judgement, and composure through setbacks, sustained workload, and adversity. Recovers quickly from disappointment or failure, learning from it rather than being defined by it, and stays steady enough to keep others steady too. Manages personal energy so effectiveness holds up over time, not just in the moment.', description_ar = 'يحافظ على الأداء والحُكم ورباطة الجأش عبر الانتكاسات وضغط العمل المستمرّ والشدائد. يتعافى بسرعة من الإحباط أو الإخفاق، متعلّماً منه لا محكوماً به، ويبقى ثابتاً بما يكفي ليثبّت الآخرين كذلك. يدير طاقته الشخصية بحيث تصمد فاعليّته عبر الزمن لا في اللحظة فقط.' WHERE id = 'a0000001-0000-0000-0000-000000000017';
UPDATE competencies SET description = 'Articulates a compelling sense of direction that connects people''s work to a larger goal and motivates action. Helps individuals see how their contribution matters and why it is worth their effort. Turns purpose into shared energy and commitment rather than leaving it as a slogan.', description_ar = 'يصوغ إحساساً مُلهِماً بالاتجاه يربط عمل الناس بهدفٍ أكبر ويحفّز على الفعل. يساعد الأفراد على رؤية أهمّية إسهامهم وسبب استحقاقه لجهدهم. يحوّل الغاية إلى طاقةٍ والتزامٍ مشتركين بدلاً من تركها شعاراً.' WHERE id = 'a0000001-0000-0000-0000-000000000018';
UPDATE competencies SET description = 'Conveys complex, strategic content clearly, tailoring the message and the medium to different audiences. Listens as well as speaks, checking for understanding rather than assuming the message landed. Adjusts tone, depth, and channel so that the right people grasp and act on what matters.', description_ar = 'ينقل المحتوى المعقّد والاستراتيجي بوضوح، مكيّفاً الرسالة ووسيلتها لمختلف الجماهير. يُحسن الإصغاء كما الكلام، ويتحقّق من الفهم بدلاً من افتراض وصول الرسالة. يضبط النبرة والعمق والقناة بحيث يستوعب الأشخاص المعنيّون ما يهمّ ويتصرّفون وفقه.' WHERE id = 'a0000001-0000-0000-0000-000000000019';
UPDATE competencies SET description = 'Builds well-reasoned, audience-aware cases that win genuine support and commitment, not just compliance. Appeals to both logic and what matters to the other party, and addresses concerns rather than overriding them. Secures buy-in that holds once the conversation is over.', description_ar = 'يبني حُججاً متماسكة تراعي الجمهور وتكسب دعماً والتزاماً حقيقيّين لا مجرّد امتثال. يخاطب المنطق وما يهمّ الطرف الآخر معاً، ويعالج المخاوف بدلاً من تجاوزها. يحقّق قبولاً يصمد بعد انتهاء النقاش.' WHERE id = 'a0000001-0000-0000-0000-000000000020';
UPDATE competencies SET description = 'Surfaces and resolves disagreement directly and calmly, preserving relationships and momentum. Treats conflict as something to work through rather than to avoid or escalate. Keeps discussion focused on the issue, not the person, so that tension becomes progress.', description_ar = 'يُظهر الخلاف ويعالجه بصورة مباشرة وهادئة، محافظاً على العلاقات والزخم. يتعامل مع الخلاف بوصفه أمراً يُعالَج لا يُتجنَّب أو يُصعَّد. يُبقي النقاش مركّزاً على المسألة لا على الشخص، بحيث يتحوّل التوتّر إلى تقدّم.' WHERE id = 'a0000001-0000-0000-0000-000000000021';
UPDATE competencies SET description = 'Reaches durable, mutually workable agreements through preparation, dialogue, and fair trade-offs. Seeks outcomes both sides can live with rather than short-term wins that damage the relationship. Holds firm on what matters while staying flexible on how to get there.', description_ar = 'يصل إلى اتفاقاتٍ متينة وقابلة للتطبيق من الطرفين عبر الإعداد والحوار والمقايضات العادلة. يسعى إلى نتائج يقبلها الجانبان بدلاً من مكاسب آنية تضرّ بالعلاقة. يتمسّك بما هو جوهري ويبقى مرناً في كيفية بلوغه.' WHERE id = 'a0000001-0000-0000-0000-000000000022';
UPDATE competencies SET description = 'Builds and sustains useful internal and external relationships that create access, insight, and influence. Invests in connections before they are needed and maintains them with genuine give-and-take, not just transactionally. Draws on a wide network to get things done and to see further than any one role allows.', description_ar = 'يبني علاقاتٍ داخلية وخارجية نافعة ويصونها بما يتيح الوصول والرؤية والتأثير. يستثمر في الصلات قبل الحاجة إليها ويحافظ عليها بأخذٍ وعطاء صادق لا بمنطق المنفعة الآنية فقط. يستند إلى شبكةٍ واسعة لإنجاز الأمور وللرؤية أبعد ممّا يتيحه أيّ دورٍ بمفرده.' WHERE id = 'a0000001-0000-0000-0000-000000000023';
UPDATE competencies SET description = 'Actively develops others toward both their own potential and the organisation''s future needs. Combines honest, specific feedback with stretching opportunities and the support to succeed in them, adapting to each person''s readiness and aspirations. Builds capability and confidence that outlast any single task and strengthen the wider talent pipeline.', description_ar = 'ينمّي الآخرين بفاعلية نحو إمكاناتهم واحتياجات المنظمة المستقبلية معاً. يجمع بين التغذية الراجعة الصادقة والمحدّدة وفرص التحدّي والدعم اللازم للنجاح فيها، مكيّفاً مقاربته مع جاهزية كلّ شخص وطموحه. يبني قدرةً وثقة تتجاوز أيّ مهمّة واحدة وتعزّز مخزون المواهب الأوسع.' WHERE id = 'a0000001-0000-0000-0000-000000000024';
UPDATE competencies SET description = 'Forms teams with a shared identity and purpose that combine diverse strengths to deliver together. Creates the conditions for trust, candour, and mutual accountability so members rely on one another. Turns a group of individuals into a team that is stronger than the sum of its parts.', description_ar = 'يكوّن فرقاً ذات هويّةٍ وغايةٍ مشتركة تجمع نقاط قوّةٍ متنوّعة لتحقيق الإنجاز معاً. يهيّئ بيئةً من الثقة والصراحة والمساءلة المتبادلة بحيث يعتمد الأعضاء بعضهم على بعض. يحوّل مجموعة من الأفراد إلى فريقٍ أقوى من مجموع أجزائه.' WHERE id = 'a0000001-0000-0000-0000-000000000025';
UPDATE competencies SET description = 'Partners across units and disciplines to achieve shared objectives over local interests. Reaches beyond their own team to coordinate, share information, and solve problems jointly. Puts the wider result ahead of silo loyalty so the organisation wins as a whole.', description_ar = 'يتشارك عبر الوحدات والتخصّصات لتحقيق أهدافٍ مشتركة تتقدّم على المصالح المحلّية. يمدّ يده إلى خارج فريقه للتنسيق وتبادل المعلومات وحلّ المشكلات بصورةٍ مشتركة. يقدّم النتيجة الأوسع على ولاء الصوامع كي تكسب المنظمة ككلّ.' WHERE id = 'a0000001-0000-0000-0000-000000000026';
UPDATE competencies SET description = 'Earns confidence through honesty, consistency, and follow-through, becoming someone others rely on. Aligns words with actions so that commitments are believed and delivered. Builds a reputation that makes collaboration and influence easier over time.', description_ar = 'يكتسب الثقة بالصدق والاتّساق والمتابعة، فيغدو شخصاً يعتمد عليه الآخرون. يوائم بين أقواله وأفعاله بحيث تُصدَّق التزاماته وتتحقّق. يبني سمعةً تجعل التعاون والتأثير أيسر مع الوقت.' WHERE id = 'a0000001-0000-0000-0000-000000000027';
UPDATE competencies SET description = 'Adjusts style and approach in the moment to fit the person and the situation without losing authenticity. Reads social cues and flexes between, for example, directness and diplomacy as the context requires. Connects effectively with a wide range of people while staying true to themselves.', description_ar = 'يكيّف أسلوبه ومقاربته في اللحظة بما يناسب الشخص والموقف دون أن يفقد أصالته. يقرأ الإشارات الاجتماعية ويتنقّل — مثلاً بين الصراحة واللباقة — وفق ما يقتضيه السياق. يتواصل بفاعلية مع طيفٍ واسع من الناس مع بقائه وفيّاً لذاته.' WHERE id = 'a0000001-0000-0000-0000-000000000028';
UPDATE competencies SET description = 'Uses feedback and honest reflection to understand own strengths, limits, and impact on others. Is open to seeing themselves clearly rather than defensively, and acts on what they learn. Turns self-awareness into deliberate growth and better-calibrated decisions.', description_ar = 'يستعين بالتغذية الراجعة والتأمّل الصادق لفهم نقاط قوّته وحدوده وأثره في الآخرين. ينفتح على رؤية نفسه بوضوح لا بدفاعية، ويتصرّف بناءً على ما يتعلّمه. يحوّل الوعي بالذات إلى نموٍّ مقصود وقراراتٍ أدقّ معايرة.' WHERE id = 'a0000001-0000-0000-0000-000000000029';
UPDATE competencies SET description = 'Recognises and manages own emotions and reads others'' accurately, responding in ways that fit the situation. Stays self-aware under emotional load and attends to how people are feeling, not only what they are saying. Builds trust and smooths interaction by responding with both control and care.', description_ar = 'يدرك انفعالاته ويديرها، ويقرأ مشاعر الآخرين بدقّة، ويستجيب بما يناسب الموقف. يبقى واعياً بذاته تحت الحِمل العاطفي ويلتفت إلى ما يشعر به الناس لا إلى ما يقولونه فقط. يبني الثقة وييسّر التفاعل باستجابةٍ تجمع بين ضبط النفس والاهتمام.' WHERE id = 'a0000001-0000-0000-0000-000000000030';
UPDATE competencies SET description = 'Raises difficult issues and says what needs to be said, even at personal or political cost. Stands up for what is right and challenges poor decisions rather than staying silent for an easier life. Acts with conviction in the face of pressure to look away.', description_ar = 'يطرح القضايا الصعبة ويقول ما يجب قوله، ولو بكلفةٍ شخصية أو سياسية. يدافع عمّا هو صواب ويتصدّى للقرارات الرديئة بدلاً من الصمت طلباً للراحة. يتصرّف بقناعةٍ في وجه الضغط للتغاضي.' WHERE id = 'a0000001-0000-0000-0000-000000000031';
UPDATE competencies SET description = 'Acts honestly and fairly, within the spirit as well as the letter of professional and regulatory standards. Holds to principle even when no one is watching or when shortcuts would be easier. Sets a standard of integrity that others can trust and follow.', description_ar = 'يتصرّف بصدقٍ وإنصاف، ملتزماً بروح المعايير المهنية والتنظيمية ونصّها معاً. يثبت على المبدأ حتى حين لا يراقبه أحد أو حين تكون المختصرات أيسر. يُرسي معياراً من النزاهة يثق به الآخرون ويقتدون به.' WHERE id = 'a0000001-0000-0000-0000-000000000032';
UPDATE competencies SET description = 'Understands and respects diverse norms and perspectives, and works inclusively across them. Adapts to different cultural and individual contexts and ensures a range of voices is heard. Draws strength from difference rather than treating it as an obstacle.', description_ar = 'يفهم الأعراف ووجهات النظر المتنوّعة ويحترمها، ويعمل بروح الشمول عبرها. يتكيّف مع السياقات الثقافية والفردية المختلفة ويضمن سماع طيفٍ من الأصوات. يستمدّ القوّة من الاختلاف بدلاً من اعتباره عائقاً.' WHERE id = 'a0000001-0000-0000-0000-000000000033';
UPDATE competencies SET description = 'Learns rapidly from new and first-time situations and applies the lessons to perform in unfamiliar conditions. Picks up unfamiliar skills, contexts, and information quickly rather than relying only on past experience. Turns each new challenge into capability that transfers to the next.', description_ar = 'يتعلّم بسرعة من المواقف الجديدة وغير المسبوقة ويطبّق الدروس للأداء في ظروفٍ غير مألوفة. يكتسب المهارات والسياقات والمعلومات الجديدة بسرعة بدلاً من الاعتماد على الخبرة السابقة وحدها. يحوّل كلّ تحدٍّ جديد إلى قدرةٍ تنتقل إلى ما يليه.' WHERE id = 'a0000001-0000-0000-0000-000000000034';
UPDATE competencies SET description = 'Actively seeks growth through formal and informal channels and applies it to raise own performance. Takes ownership of their own development rather than waiting for it to be provided. Keeps building relevant skills so they stay effective as demands change.', description_ar = 'يسعى بنشاط إلى النموّ عبر القنوات الرسمية وغير الرسمية ويطبّقه لرفع أدائه. يتولّى مسؤولية تطوير ذاته بدلاً من انتظار أن يُقدَّم له. يواصل بناء المهارات ذات الصلة ليبقى فاعلاً مع تغيّر المتطلّبات.' WHERE id = 'a0000001-0000-0000-0000-000000000035';
UPDATE competencies SET description = 'Stays calm, clear, and constructive when under pressure or scrutiny. Keeps emotion in check in tense moments so that thinking stays sharp and behaviour stays professional. Provides a steadying presence that reassures others when stakes are high.', description_ar = 'يبقى هادئاً وواضحاً وبنّاءً تحت الضغط أو التدقيق. يضبط انفعاله في اللحظات المتوتّرة بحيث يبقى تفكيره حادّاً وسلوكه مهنيّاً. يوفّر حضوراً مطمئِناً يبثّ الثقة في الآخرين حين تعلو المخاطر.' WHERE id = 'a0000001-0000-0000-0000-000000000036';
UPDATE competencies SET description = 'Manages energy and the competing demands of work and life to sustain performance over time. Sets boundaries and recovers deliberately rather than running on empty until something breaks. Protects the long-term capacity to perform, for themselves and as an example to others.', description_ar = 'يدير طاقته والمتطلّبات المتنافسة للعمل والحياة للحفاظ على الأداء عبر الزمن. يضع حدوداً ويستعيد عافيته عن قصد بدلاً من الاستنزاف حتى الانهيار. يحمي القدرة على الأداء بعيدة المدى لنفسه وكقدوةٍ للآخرين.' WHERE id = 'a0000001-0000-0000-0000-000000000037';
UPDATE competencies SET description = 'Secures and deploys the people, budget, and tools needed to get work done effectively. Makes the case for resources where they will have the most impact and removes practical obstacles to delivery. Ensures teams have what they need to succeed rather than leaving them under-equipped.', description_ar = 'يؤمّن ما يلزم من أشخاصٍ وميزانية وأدوات وينشرها لإنجاز العمل بفاعلية. يقدّم المبرّر لتخصيص الموارد حيث يكون أثرها أكبر، ويزيل العقبات العملية أمام التنفيذ. يضمن أن يمتلك الفريق ما يحتاجه للنجاح بدلاً من تركه ناقص التجهيز.' WHERE id = 'a0000001-0000-0000-0000-000000000038';
UPDATE competencies SET description = 'Understands and anticipates customer needs and delivers exceptional, reliable service against them. Builds relationships on responsiveness and follow-through, treating the customer''s experience as a measure of success. Keeps the customer at the centre of decisions rather than as an afterthought.', description_ar = 'يفهم احتياجات العملاء ويستبقها، ويقدّم خدمةً متميّزة وموثوقة تلبّيها. يبني العلاقات على سرعة الاستجابة والمتابعة، ويتعامل مع تجربة العميل بوصفها مقياساً للنجاح. يُبقي العميل في صميم القرارات لا على هامشها.' WHERE id = 'a0000001-0000-0000-0000-000000000039';
UPDATE competencies SET description = 'Identifies, aligns, and manages internal and external stakeholders with tact and trust. Maps who is affected by and who can affect a piece of work, and engages each appropriately and early. Keeps diverse interests aligned around shared goals so that delivery is not derailed by competing agendas.', description_ar = 'يحدّد أصحاب المصلحة الداخليّين والخارجيّين ويوائم بينهم ويديرهم بلباقةٍ وثقة. يرسم خريطةً لمن يتأثّر بالعمل ومن يؤثّر فيه، ويُشرك كلّاً منهم على نحوٍ مناسب وفي وقتٍ مبكّر. يُبقي المصالح المتنوّعة متوائمة حول أهدافٍ مشتركة كي لا يتعثّر التنفيذ بفعل الأجندات المتنافسة.' WHERE id = 'a0000001-0000-0000-0000-000000000040';
UPDATE competencies SET description = 'Focuses on sustainable value, linking day-to-day work to commercial outcomes and the wider business value chain. Weighs effort against the return it produces and steers attention to what genuinely moves the organisation forward. Looks beyond activity to the lasting value the work creates.', description_ar = 'يركّز على القيمة المستدامة، رابطاً العمل اليومي بالنتائج التجارية وسلسلة القيمة الأوسع للأعمال. يوازن بين الجهد والعائد الذي يحقّقه، ويوجّه الاهتمام إلى ما يدفع المنظمة فعلاً إلى الأمام. ينظر إلى ما هو أبعد من النشاط نحو القيمة الدائمة التي يخلقها العمل.' WHERE id = 'a0000001-0000-0000-0000-000000000041';
